        // Paint handler for the column header bottom border
        // (defined here so the Designer doesn't complain about lambdas)
        private void pnlColHeaders_Paint(object sender, PaintEventArgs e)
        {
            using var pen = new Pen(Color.FromArgb(226, 232, 240), 1);
            e.Graphics.DrawLine(pen, 0, pnlColHeaders.Height - 1,
                pnlColHeaders.Width, pnlColHeaders.Height - 1);
        }

